import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2009年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2009年/核心总结.md","filePath":"01_letters/2009年/核心总结.md"}'),o={name:"01_letters/2009年/核心总结.md"};function r(u,l,h,n,s,d){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2009年巴菲特致股东信核心总结" tabindex="-1">2009年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2009年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2009年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增加218亿美元，每股账面价值增长19.8%</li><li>45年复合增长率20.3%</li><li>BNSF收购增加至少65,000名股东，股东总数约50万</li></ul><h2 id="主要投资决策" tabindex="-1">主要投资决策 <a class="header-anchor" href="#主要投资决策" aria-label="Permalink to &quot;主要投资决策&quot;">​</a></h2><h3 id="重大收购-bnsf铁路" tabindex="-1">重大收购：BNSF铁路 <a class="header-anchor" href="#重大收购-bnsf铁路" aria-label="Permalink to &quot;重大收购：BNSF铁路&quot;">​</a></h3><ul><li>伯灵顿北方圣太菲铁路公司</li><li>伯克希尔历史上最大收购之一</li><li>拥有约257,000名员工</li></ul><h3 id="危机中的投资" tabindex="-1">危机中的投资 <a class="header-anchor" href="#危机中的投资" aria-label="Permalink to &quot;危机中的投资&quot;">​</a></h3><ul><li>2008年危机顶峰投入155亿美元</li><li>90亿美元支持高盛、通用电气、箭牌</li><li>展现伯克希尔的财务实力</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><h3 id="逆向思维" tabindex="-1">逆向思维 <a class="header-anchor" href="#逆向思维" aria-label="Permalink to &quot;逆向思维&quot;">​</a></h3><ul><li>查理·芒格：&quot;我只想知道我会死在哪里，这样我就永远不会去那里&quot;</li><li>&quot;逆向，始终逆向&quot;——解决困难问题的方法</li></ul><h3 id="我们不做什么" tabindex="-1">我们不做什么 <a class="header-anchor" href="#我们不做什么" aria-label="Permalink to &quot;我们不做什么&quot;">​</a></h3><ol><li><p><strong>避免无法评估未来的企业</strong></p><ul><li>行业增长不等于投资成功</li><li>竞争动态可能摧毁所有参与者</li></ul></li><li><p><strong>不依赖陌生人的善意</strong></p><ul><li>保持首屈一指的财务实力</li><li>持有200多亿美元现金</li></ul></li><li><p><strong>分权管理</strong></p><ul><li>子公司自主运营</li><li>宁愿承受可见成本，不愿因繁文缛节错失机会</li></ul></li><li><p><strong>不取悦华尔街</strong></p><ul><li>直接翔实地与股东沟通</li><li>批评简讯式新闻报道的误导</li></ul></li></ol><h3 id="衡量标准" tabindex="-1">衡量标准 <a class="header-anchor" href="#衡量标准" aria-label="Permalink to &quot;衡量标准&quot;">​</a></h3><ul><li>选择标普500作为基准</li><li>每股账面价值追踪内在价值变化</li><li>45年数据：防守比进攻更好（指数下跌11年均战胜）</li></ul><h3 id="规模的挑战" tabindex="-1">规模的挑战 <a class="header-anchor" href="#规模的挑战" aria-label="Permalink to &quot;规模的挑战&quot;">​</a></h3><ul><li>&quot;巨额资金会自己铸造锚索&quot;</li><li>未来优势将只是历史优势的一小部分</li><li>但独特企业文化将继续产生高于平均的结果</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金奇迹" tabindex="-1">浮存金奇迹 <a class="header-anchor" href="#浮存金奇迹" aria-label="Permalink to &quot;浮存金奇迹&quot;">​</a></h3><ul><li>从1967年的1,600万美元增至620亿美元</li><li>连续七年承保盈利</li><li>&quot;免费的浮存金&quot;——持有别人资金还能获得报酬</li></ul><h3 id="保险明星" tabindex="-1">保险明星 <a class="header-anchor" href="#保险明星" aria-label="Permalink to &quot;保险明星&quot;">​</a></h3><ol><li><p><strong>GEICO</strong>：Tony Nicely</p><ul><li>市场份额从2.5%（1995）增至8.1%</li><li>14年中13年承保盈利</li></ul></li><li><p><strong>Ajit Jain</strong>：再保险巨头</p><ul><li>30人团队创造独特业务</li><li>劳合社Equitas交易保费71亿美元</li><li>人寿再保险合约可能50年带来500亿美元保费</li></ul></li><li><p><strong>General Re</strong>：Tad Montross</p><ul><li>从困境到&quot;保险皇冠上的明珠&quot;</li><li>取得Cologne Re 100%所有权</li></ul></li></ol><h2 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h2><h3 id="企业评估" tabindex="-1">企业评估 <a class="header-anchor" href="#企业评估" aria-label="Permalink to &quot;企业评估&quot;">​</a></h3><ul><li>坚持未来几十年利润前景可预测的企业</li><li>避免依赖伟大经理人的企业</li><li>寻找持久护城河</li></ul><h3 id="沟通原则" tabindex="-1">沟通原则 <a class="header-anchor" href="#沟通原则" aria-label="Permalink to &quot;沟通原则&quot;">​</a></h3><ul><li>在周末发布财务信息，给投资者充足消化时间</li><li>直接、翔实、不加删减</li><li>批评断章取义的媒体报道</li></ul><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;我只想知道我会死在哪里，这样我就永远不会去那里。&quot;</p></blockquote><blockquote><p>&quot;如果查理、我和Ajit同在一条沉船上——而你只能救我们中的一个——游向Ajit。&quot;</p></blockquote><blockquote><p>&quot;巨大的资金会自己铸造锚索，我们未来的优势将只是历史优势的一小部分。&quot;</p></blockquote><blockquote><p>&quot;倒唱一首乡村歌曲，你会很快找回你的车、房子和妻子。&quot;</p></blockquote><hr><p><em>生成日期：2026年4月</em></p>',34)])])}const b=a(o,[["render",r]]);export{c as __pageData,b as default};
